// Artikel aus dem Excel-Format extrahieren
// Unterstuetzt Dateien mit und ohne 'Tagesangebote:'-Zeile
const rows = $input.all().map(i => i.json);
let artikel = [];
let kategorie = 'Allgemein';
let id = 1;
let startParsing = false;
let datumMatch = null;

for (const row of rows) {
  const values = Object.values(row);
  const joined = values.join(' ').trim();

  if (!joined) continue;

  // Lieferdatum suchen (z.B. in Header-Zeilen)
  if (!datumMatch) {
    const dMatch = joined.match(/(\d{1,2}[.\/]\d{1,2}[.\/]\d{2,4})/);
    if (dMatch) datumMatch = dMatch[1];
  }

  // Spaltenheader erkennen -> ab naechster Zeile parsen
  const lower = joined.toLowerCase();
  if (lower.includes('artikel') && lower.includes('preis')) {
    startParsing = true;
    continue;
  }

  if (!startParsing) continue;

  // Ende erkennen
  if (lower.includes('gesamt zu zahlen') || lower.includes('gesamtsumme')) break;

  // Kategorie-Wechsel: 'Tagesangebote' oder andere Kategoriezeilen
  if (lower.includes('tagesangebote')) {
    kategorie = 'Tagesangebote';
    continue;
  }

  // Weitere Kategorie-Marker erkennen (Zeile mit Text aber ohne Preis)
  const col_B = values[1];
  const col_D = values[3];
  const textOnly = col_B && String(col_B).trim() !== '' && (!col_D || String(col_D).trim() === '');
  const col_A = values[0];
  const hasNoQty = !col_A || String(col_A).trim() === '';
  if (textOnly && hasNoQty && String(col_B).trim().endsWith(':')) {
    kategorie = String(col_B).trim().replace(/:$/, '');
    continue;
  }

  // Leere Zeile ueberspringen
  if (!col_B || String(col_B).trim() === '') continue;

  const preis = parseFloat(String(col_D || '0').replace(',', '.'));
  if (isNaN(preis) || preis <= 0) continue;

  const col_C = values[2];
  artikel.push({
    id: id++,
    name: String(col_B).trim(),
    einheit: String(col_C || '').trim() || 'Stueck',
    preis: Math.round(preis * 100) / 100,
    kategorie: kategorie
  });
}

// In Static Data speichern (geteilt mit allen Triggern im Workflow)
const staticData = $getWorkflowStaticData('global');
staticData.artikel = artikel;
staticData.bestellungen = {};
staticData.tokens = {};
staticData.bestellung_aktiv = true;
staticData.kaeufer = staticData.kaeufer || [];
staticData.angebot_datum = datumMatch || new Date().toLocaleDateString('de-DE');
staticData.webapp_url = staticData.webapp_url || 'https://jade-alfajores-4f3440.netlify.app';

return [{ json: { 
  artikel_count: artikel.length, 
  datum: staticData.angebot_datum,
  artikel: artikel 
}}];

// Kaeufer-Liste aus Static Data laden
const staticData = $getWorkflowStaticData('global');
const kaeufer = staticData.kaeufer || [];

if (kaeufer.length === 0) {
  return [{ json: { skip: true, message: 'Keine Kaeufer registriert' } }];
}

return kaeufer.map(chatId => ({
  json: {
    chatId: String(chatId),
    datum: staticData.angebot_datum,
    artikelCount: (staticData.artikel || []).length,
    webapp_url: staticData.webapp_url || 'https://jade-alfajores-4f3440.netlify.app'
  }
}));

// Artikeldaten direkt aus geteilter Static Data lesen
const staticData = $getWorkflowStaticData('global');

return [{ json: {
  artikel: staticData.artikel || [],
  bestellung_aktiv: staticData.bestellung_aktiv !== false,
  angebot_datum: staticData.angebot_datum || '',
  timestamp: new Date().toISOString()
}}];

// POST: Bestellung speichern (direkt in geteilter Static Data)
const body = $input.first().json.body || $input.first().json;
const staticData = $getWorkflowStaticData('global');

// Prüfe ob Bestellung aktiv
if (staticData.bestellung_aktiv === false) {
  return [{ json: { error: 'Bestellfenster geschlossen', status: 403 } }];
}

const chatId = body.chatId;
if (!chatId) {
  return [{ json: { error: 'Chat-ID fehlt', status: 400 } }];
}

// Token generieren oder bestehenden verwenden
let token = body.token;
const bestellungen = staticData.bestellungen || {};
const tokens = staticData.tokens || {};

if (!token || !tokens[token]) {
  token = 'ord_' + Math.random().toString(36).substr(2, 12) + Date.now().toString(36);
}

// Bestellung speichern
bestellungen[chatId] = {
  chatId: chatId,
  userName: body.userName || 'Unbekannt',
  positionen: body.positionen || [],
  gesamtpreis: body.gesamtpreis || 0,
  token: token,
  zeitpunkt: body.zeitpunkt || new Date().toISOString(),
  aktualisiert: new Date().toISOString()
};

tokens[token] = chatId;

// Kaeufer registrieren (wenn noch nicht vorhanden)
const kaeufer = staticData.kaeufer || [];
if (!kaeufer.includes(String(chatId))) {
  kaeufer.push(String(chatId));
}

staticData.bestellungen = bestellungen;
staticData.tokens = tokens;
staticData.kaeufer = kaeufer;

const isUpdate = !!body.token;

// Prüfe auf ungewoehnlich hohe Mengen (>50 Einheiten)
const highQtyItems = (body.positionen || []).filter(p => p.menge > 50);

return [{ json: {
  success: true,
  token: token,
  chatId: String(chatId),
  userName: body.userName,
  gesamtpreis: body.gesamtpreis,
  isUpdate: isUpdate,
  highQtyWarning: highQtyItems.length > 0,
  highQtyItems: highQtyItems.map(p => p.name + ' (' + p.menge + 'x)').join(', '),
  webapp_url: staticData.webapp_url || 'https://jade-alfajores-4f3440.netlify.app',
  status: 200
}}];

