// Bestellfenster schliessen und Daten bereinigen (direkt in Static Data)
const staticData = $getWorkflowStaticData('global');
staticData.bestellungen = {};
staticData.tokens = {};
staticData.bestellung_aktiv = false;
// Kaeufer bleiben erhalten fuer naechste Woche
return [{ json: { success: true, message: 'Bestellungen geschlossen und bereinigt' } }];

// Bestellfenster schliessen (keine Bestellungen)
const staticData = $getWorkflowStaticData('global');
staticData.bestellungen = {};
staticData.tokens = {};
staticData.bestellung_aktiv = false;
return [{ json: { success: true } }];

// Bestellung per Token laden (direkt aus geteilter Static Data)
const query = $('Webhook GET Bestellung').first().json.query || {};
const token = query.token;

if (!token) {
  return [{ json: { 
    error: 'Token parameter fehlt', 
    code: 400 
  }}];
}

const staticData = $getWorkflowStaticData('global');
const tokens = staticData.tokens || {};
const chatId = tokens[token];

if (!chatId) {
  return [{ json: { 
    error: 'Ungueltiger oder abgelaufener Token', 
    code: 404 
  }}];
}

const bestellungen = staticData.bestellungen || {};
const bestellung = bestellungen[chatId];

if (!bestellung) {
  return [{ json: { 
    error: 'Bestellung nicht gefunden', 
    code: 404 
  }}];
}

return [{ json: {
  chatId: bestellung.chatId,
  userName: bestellung.userName,
  positionen: bestellung.positionen,
  gesamtpreis: bestellung.gesamtpreis,
  token: token,
  zeitpunkt: bestellung.zeitpunkt,
  code: 200
}}];
